// Factory function to create region checkers
function createRegionChecker(azureClient, resourceType, properties) {
    const provider = resourceType.split('/')[0].toLowerCase();
    switch (provider) {
        case "microsoft.cognitiveservices":
            return new CognitiveServicesRegionChecker(azureClient, properties?.deploymentSkuName, properties?.modelVersion, properties?.modelName);
        case "microsoft.dbforpostgresql":
            return new PostgresSQLRegionChecker(azureClient);
        case "microsoft.sql":
            return new SQLChecker(azureClient);
        case "microsoft.dbformysql":
            return new MysqlRegionChecker(azureClient);
        case "microsoft.documentdb":
            return new DocumentDBRegionChecker(azureClient);
        case "microsoft.compute":
            return new ComputeChecker(azureClient);
        case "appservicemanagedinstance":
            return new AppServiceManagedInstanceRegionChecker(azureClient);
        default:
            return new DefaultRegionChecker(azureClient);
    }
}
// Main function to get available regions for resource types
async function getAvailableRegionsForResourceTypes(resourceTypes, azureClient, cognitiveServiceProperties, assignedRegions) {
    const regionCheckPromises = resourceTypes.map(async (resourceType) => {
        try {
            const checker = createRegionChecker(azureClient, resourceType, cognitiveServiceProperties);
            const regions = await checker.getAvailableRegions(resourceType, assignedRegions);
            return regions;
        }
        catch (error) {
            return [];
        }
    });
    const availableRegions = await Promise.all(regionCheckPromises);
    const allRegions = availableRegions.filter(regions => regions.length > 0);
    // List regions that are available for all resource types
    let validRegions = allRegions[0];
    for (const availableRegionSet of allRegions) {
        validRegions = validRegions.filter(x => availableRegionSet.includes(x));
    }
    return validRegions;
}
// Enhanced function to get both common regions and per-resource-type breakdown
async function getAvailableRegionsByResourceTypes(resourceTypes, azureClient, cognitiveServiceProperties, assignedRegions) {
    const regionCheckPromises = resourceTypes.map(async (resourceType) => {
        try {
            const checker = createRegionChecker(azureClient, resourceType, cognitiveServiceProperties);
            const regions = await checker.getAvailableRegions(resourceType, assignedRegions);
            return { resourceType, regions };
        }
        catch (error) {
            return { resourceType, regions: [] };
        }
    });
    const resourceRegionResults = await Promise.all(regionCheckPromises);
    // Create the per-resource-type breakdown
    const regionsByResourceType = {};
    resourceRegionResults.forEach(result => {
        regionsByResourceType[result.resourceType] = result.regions;
    });
    // Calculate common regions (intersection of all resource types)
    const allRegions = resourceRegionResults.map(result => result.regions).filter(regions => regions.length > 0);
    let commonRegions = allRegions[0] || [];
    for (const availableRegionSet of allRegions) {
        commonRegions = commonRegions.filter(x => availableRegionSet.includes(x));
    }
    return { commonRegions, regionsByResourceType };
}
async function getAllRegions(azureClient) {
    const requestUrl = `https://management.azure.com/subscriptions/${azureClient.getCurrentSubscriptionId()}/locations?api-version=2022-12-01`;
    const data = await azureClient.queryManagementPlane(requestUrl);
    if (data && data.value) {
        return data.value.map((location) => location.name);
    }
    return [];
}
